var Container = require('../../../com/container/container');
var context = require('../context');
var AllMsg = function(){};

Container._extend(AllMsg, {
  _className: 'allmsg',
  __filename: __filename,
  initData: function(){
    this.data = {
      url: context.urls
    };
  },
  initEvents: function(){
    AllMsg.prototype._super.initEvents.call(this);
  },
  afterComplete : function(){
    AllMsg.prototype._super.afterComplete.call(this);
    var table = this.query("*[name=allSelectTab]");
    table.store.loadPage(1, {});
  }
});

exports = module.exports = AllMsg;

